-- 4.2.1 Отдел выявления операций обязательного контроля
WITH ins AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.2.1'
  FROM (VALUES
    ('Обеспечение своевременного выявления и квалификации операций, подлежащих обязательному контролю, по клиентам Банка путём ежедневного мониторинга проведённых операций в автоматизированной системе Банка','control'),
    ('Формирование отчётов в виде формализованных электронных сообщений (ФЭС) в порядке, установленном Банком России по согласованию с Уполномоченным органом, в части клиентов Банка','operational'),
    ('Осуществление контроля полноты и своевременности выявления и формирования УФМ СЦ ФЭС, содержащих сведения об операциях, подлежащих обязательному контролю, посредством специализированных программных средств','control'),
    ('Осуществление контроля корректности заполнения полей, сформированных УФМ СЦ ФЭС по операциям, подлежащим обязательному контролю, а также о случаях отказа от заключения договора банковского счёта (вклада), отказа в совершении операции, расторжения договора банковского счёта (вклада) с клиентом по инициативе Банка в части клиентов подразделений региональной сети Банка с целью минимизации случаев отбраковки сообщений Уполномоченным органом','control'),
    ('Осуществление полного контроля сформированных УФМ СЦ ФЭС по подозрительным операциям (сделкам) клиентов структурных подразделений региональной сети Банка с целью минимизации случаев отбраковки сообщений Уполномоченным органом с использованием специализированных программных средств','control')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins.id, u.id, 'owner', 'polozhenie'
FROM ins JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.2.1' AND u.is_archived = false;

-- 4.2.2 Отдел формирования отчётности
WITH ins2 AS (
  INSERT INTO t_p61016064_digital_innovation_i.dept_functions (project_id, dept_name, title, category, source_section_code)
  SELECT 1, 'Департамент финансового мониторинга (ДФМ)', v.title, v.category, '4.2.2'
  FROM (VALUES
    ('Обеспечение своевременного направления ФЭС в Уполномоченный орган и получение извещений в виде электронных сообщений из Уполномоченного органа в установленные законодательством Российской Федерации сроки','operational'),
    ('Осуществление с использованием специализированных программных средств контроля на корректность формирования ФЭС на основании форматно-логического контроля','control'),
    ('Инициирование доработки специализированных программных комплексов Банка в связи с изменениями законодательства Российской Федерации в сфере ПОД/ФТ, в части, касающейся деятельности Отдела формирования отчётности','operational'),
    ('Направление в установленные законодательством Российской Федерации сроки с использованием специализированных программных средств сведений в Уполномоченный орган в порядке, установленном Банком России по согласованию с Уполномоченным органом','operational'),
    ('Организация обработки поступающих из Уполномоченного органа запросов, сформированных в порядке, установленном Банком России по согласованию с Уполномоченным органом','operational'),
    ('Осуществление сбора и подготовки документов и (или) информации и предоставление ответов на запросы Уполномоченного органа','communication'),
    ('Осуществление консультирования работников структурных подразделений Банка по вопросам подготовки документов и (или) информации, подлежащих предоставлению в составе ответов на запросы Уполномоченного органа','communication')
  ) AS v(title, category)
  RETURNING id, source_section_code
)
INSERT INTO t_p61016064_digital_innovation_i.function_org_units (function_id, org_unit_id, role, source_ref)
SELECT ins2.id, u.id, 'owner', 'polozhenie'
FROM ins2 JOIN t_p61016064_digital_innovation_i.org_units u
  ON u.project_id = 1 AND u.code = '4.2.2' AND u.is_archived = false;